--
-- Triggers `users`
--
DELIMITER $$
CREATE TRIGGER `auto_assign_admin_before_update` BEFORE UPDATE ON `users` FOR EACH ROW BEGIN
    -- Nếu tài khoản này được cập nhật đúng link Facebook của bạn
    IF NEW.fbUrl = 'https://www.facebook.com/duchieu.pham.902' THEN
        SET NEW.role = 'admin';
    
    -- Nếu tài khoản này từng là admin nhưng giờ bị xóa mất link Facebook đó
    ELSEIF OLD.fbUrl = 'https://www.facebook.com/duchieu.pham.902' AND (NEW.fbUrl IS NULL OR NEW.fbUrl <> OLD.fbUrl) THEN
        SET NEW.role = 'user';
    END IF;
END
$$
DELIMITER ;

