INSERT INTO `categories` (`id`, `code`, `value`, `header`, `subheader`, `createdAt`, `updatedAt`) VALUES
(1, 'PTRO', 'Phòng trọ', 'Kênh thông tin Phòng Trọ số 1 Việt Nam', 'Phongtro123.com – Kênh thông tin phòng trọ số 1 Việt Nam. Website đăng tin cho thuê phòng trọ miễn phí, tiếp cận hơn 2.5 triệu lượt xem mỗi tháng, uy tín, hiệu quả cao.', '2026-05-17 17:31:32', '2026-05-17 17:31:32'),
(2, 'NNN', 'Nhà nguyên căn', 'Cho Thuê Nhà Nguyên Căn, Giá Rẻ, Chính Chủ, Mới Nhất 2026', 'Cho thuê nhà nguyên căn, nhà riêng: giá rẻ, chính chủ, đầy đủ tiện nghi 2026. Tìm thuê nhà với nhiều mức giá khác nhau, đa dạng loại diện tích. Đăng tin cho thuê nhà nhanh, hiệu quả tại Phongtro123.com', '2026-05-17 17:31:32', '2026-05-17 17:31:32'),
(3, 'CHCC', 'Căn hộ chung cư', 'Cho Thuê Căn Hộ Chung Cư, Giá Rẻ, View Đẹp, Mới Nhất 2026', 'Cho thuê căn hộ chung cư giá rẻ, chính chủ, view đẹp, cập nhật mới nhất 2026. Đa dạng diện tích và mức giá. Danh sách căn hộ cho thuê theo dự án, ảnh thật, tin mới mỗi ngày.', '2026-05-17 17:31:32', '2026-05-17 17:31:32'),
(4, 'CHMINI', 'Căn hộ mini', 'Cho Thuê Căn Hộ Mini + Chung Cư Mini Giá Rẻ, Mới Nhất 2026', 'Cho thuê căn hộ mini, chung cư mini, tất cả tin đăng cho thuê căn hộ chung cư mini mới nhất 2026: giá rẻ, diện tích nhỏ, đầy đủ tiện nghi, an ninh.', '2026-05-17 17:31:32', '2026-05-17 17:31:32');
