('f92077b2-51e9-4a69-85f5-698cccf8a4e6', 'Chủ nhà cho thuê căn hộ mini khép kín 50 m2 Đường Cổ nhuế', '0', 'NUHD', 'ee6ed11b-4f29-44d1-91c3-7da7e65144b4', 'CHMINI', '5U7N', '5UMD', 'NDOE', '[\"CĂN HỘ KHÉP KÍN 50m² – FULL NỘI THẤT – BẮC TỪ LIÊM\",\"Cổ Nhuế (Đông Ngạc), Bắc Từ Liêm, Hà Nội\",\"Diện tích 50m², thiết kế riêng: phòng ngủ – phòng khách – bếp\",\"Không gian thoáng, có cửa sổ\",\"Full nội thất, dọn vào ở ngay\",\"* Tiện ích:\",\"Chỗ để xe riêng\",\"Giờ giấc tự do, không chung chủ\",\"Điện, nước tính theo đồng hồ riêng\",\"* Vị trí:\",\"Gần trường mầm non, tiểu học Cổ Nhuế\",\"Kết nối nhanh ra Phạm Văn Đồng\"]', '4c9faa65-73a1-4534-91a2-f2df547a73b5', '021e9385-f8e5-4551-942c-f9daab79a49b', '3078ca80-07e1-4644-9e7c-5a632a9e6f01', 5.4, 50, '2026-06-04 14:08:58', '2026-06-04 14:08:58', 0, 'active'),
('fb6e751e-cde1-4541-9b54-5b513590d033', 'Cho thuê CH mini, 1PN, 1WC, 35m2, giá chỉ từ 5,8triệu tại 444 Thụy Khuê, hàng hot!', '0', 'NUHD', '4b4638c5-48fb-4c33-81fe-8936f41d1380', 'CHMINI', '5U7N', '3UMD', 'NDOE', '[\"CH mini cho thuê ở 444 Thuỵ Khuê, Đường Thụy Khuê, Phường Tây Hồ, Hà Nội (Quận Tây Hồ, Hà Nội cũ) rất xịn xò với 1PN, 1WC, diện tích 35m². Giá chỉ 5,8tr - 7,5tr, cực kỳ hợp lý cho không gian sống thoải mái. Thời gian thuê linh hoạt, hợp đồng 3-6-9-12 tháng, nên thoải mái lựa chọn.\",\"Hình thức: đóng 1 cọc 1.\",\"Tiện ích xung quanh:\",\"- Gần bệnh viện phổi trung ương, bệnh viện quân y 354, tci hospital - bệnh viện đa khoa quốc tế thu cúc\",\"- Công viên Bách Thảo để chill và thư giãn\",\"- Siêu thị Teekiu Mart, Winmart+, Fujimart Thụy Khuê cho những ai thích mua sắm\",\"- Tiện di chuyển nội thành trung tâm, ra hồ Tây vài trăm mét.\",\"Liên hệ ngay để được tư vấn miễn phí: Ha Huy\"]', '8d3d556f-1771-498e-bef9-e567f1fd410d', '14d8473a-fda5-4ccd-8a69-3988b9229a7b', 'e5bbcc53-f773-40a6-b729-c60eac873daf', 5.8, 35, '2026-06-04 14:08:59', '2026-06-04 14:08:59', 0, 'active'),
('fbf8f12a-d837-4994-ad95-1c169d3922d0', 'Cho thuê nhà riêng tại NGÕ 189 Hoàng Hoa Thám', '0', 'NUHD', 'ce488cb0-2058-40f4-8ce1-98be24830190', 'NNN', '7U0N', '2UMD', 'NDOE', '[\"Cho thuê nhà riêng tại NGÕ 189 HOÀNG HOA THÁM\",\"Nhà riêng cho thuê tại NGÕ 189 HOÀNG HOA THÁM, Đường Hoàng Hoa Thám, Phường Ba Đình, Hà Nội (cũ: Quận Ba Đình, Hà Nội) với các đặc điểm nổi bật như sau:\",\"- Diện tích 20m2, 4PN, 3WC, 4 tầng, hướng Tây Nam.\",\"- Nội thất cơ bản với điều hòa, tủ lạnh, giường,...\",\"- Mặt tiền 3m, thích hợp cho việc kinh doanh.\",\"- Thời gian thuê linh hoạt, tối thiểu 1 năm.\",\"Tiện ích xung quanh:\",\"- Gần bệnh viện phổi trung ương, bệnh viện đa khoa quốc tế thu cúc, bệnh viện quân y 354.\",\"- Siêu thị Fujimart Thụy Khuê, Teekiu Mart, Winmart+.\",\"- Công viên Bách Thảo.\",\"- Trung tâm nghệ thuật Adam, UB Academy - trung tâm đào tạo nghiệp vụ ngân hàng tài chính.\",\"Liên hệ để biết thêm chi tiết: 0976278395 Việt Anh Nguyễn\"]', '7002d6a6-85a3-4fda-a4e7-4345d3522dd5', 'c5290e63-87fb-416e-97cc-cfa28314a019', 'c1438254-df1d-4325-90c6-388bd8ac6ee4', 8.5, 20, '2026-06-04 14:08:47', '2026-06-04 14:08:47', 0, 'active'),
('fc991059-5e5e-4ee0-86ca-307db9c32bcb', 'CĂN HỘ 1 PHÒNG NGỦ 1 PHÒNG KHÁCH GẦN CẦU SÀI GÒN ĐƯỜNG BÌNH QUỚI, BÌNH THẠNH', '0', 'NUHD', '4581a8d0-397e-45a2-a1fe-d25c009eb12f', 'CHMINI', '7U0N', '3UMD', 'CUID', '[\"Đường Bình Quới, Bình Thạnh – khu yên tĩnh, thoáng mát, cực dễ sống\",\"Điểm cộng xịn:\",\"– 1 phòng ngủ + 1 phòng khách riêng biệt, không gian rõ ràng\",\"– Phòng rộng, ở thoải mái 2–3 người\",\"– Nội thất đầy đủ, chỉ việc xách vali vào ở\",\"– Khu vực an ninh, ít ồn, vibe chill đúng nghĩa\",\"Vị trí tiện:\",\"– Gần Cầu Sài Gòn, di chuyển qua Thảo Điền – Q2 cực nhanh\",\"– Thuận tiện đi Q1, Q3, Phú Nhuận\",\"– Gần chợ, siêu thị, quán ăn, cà phê đủ hết\"]', 'ba63bc98-27d7-4c16-b832-e2fa8b8f94b1', '49168fae-3be5-45ab-95eb-c3e790533224', 'a11f7fb8-ae1d-4891-8a71-50e0fa47a565', 8.5, 40, '2026-06-04 14:08:57', '2026-06-04 14:08:57', 0, 'active');
